  // Helper function to mark profile form as dirty and update timestamp
  const markProfileDirty = () => {
    setProfileFormState('profile_dirty');
    setLastProfileUpdateTimestamp(Date.now());
    // Clear any existing auto-save timer - it will be reset by the useEffect
    if (profileAutoSaveTimerRef.current) {
      clearTimeout(profileAutoSaveTimerRef.current);
      profileAutoSaveTimerRef.current = null;
    }
  };
  
  // Shorten a URL via the /api/shorten proxy and update the given setter
  const shortenUrl = async (url: string, setter: (val: string) => void, fieldId: string) => {
    if (!url || !url.startsWith('http')) return;
    setShorteningUrlId(fieldId);
    try {
      const response = await fetch(`/api/shorten?url=${encodeURIComponent(url)}`);
      if (response.ok) {
        const data = await response.json();
        setter(data.shortened);
        markProfileDirty();
      }
    } catch (e) {
      console.error('Failed to shorten URL:', e);
    } finally {
      setShorteningUrlId(null);
    }
  };

